func dispatchWp_(slot uint32, recv unsafe.Pointer, w0 unsafe.Pointer) {
	var pw [1]unsafe.Pointer
	var sw [0]uint64
	var fw [0]float64
	pw[0] = w0
	var rpw [0]unsafe.Pointer
	var rsw [0]uint64
	var rfw [0]float64
	if core := slotPoolWp_[slot]; core != nil {
		core(recv, pw[:], sw[:], fw[:], rpw[:], rsw[:], rfw[:])
	}
}

